import{$,$$,emit,t,getLang,storage,toast,ICONS,appLabel,}from"./utils.js";import*as story from"./story.js";import{mountFloats}from"./ingredients.js";let data=null;const REQUIRED=["id","name","image","background"];export function getData(){return data;}
export function getSignatureDish(){if(!data)return null;return data.dishes.find((d)=>d.signature)??data.dishes.find((d)=>d.chefChoice)??null;}
async function fetchJSON(path,optional=false){try{const res=await fetch(path,{cache:"no-cache"});if(!res.ok)throw new Error(`${path} ${res.status}`);return await res.json();}catch(err){if(optional){console.warn(`[kristo] ${path} unavailable`,err);return null;}
throw err;}}
export async function loadData(){const[brand,social,settings,categories,menuData,prices]=await Promise.all([fetchJSON("data/brand.json",true),fetchJSON("data/social.json",true),fetchJSON("data/settings.json",true),fetchJSON("data/categories.json",true),fetchJSON("data/menu.json"),fetchJSON("data/prices.json",true),]);data=menuData;data.restaurant={...(brand||{}),...(social||{}),orderLinks:settings?.orderLinks||{},};data.categories=(categories||[]).slice().sort((a,b)=>(a.order??0)-(b.order??0));const priceOf=(id)=>{const p=prices?.[id];return typeof p==="number"&&p>0?p:null;};data.dishes=(data.dishes||[]).filter((d)=>{const ok=REQUIRED.every((k)=>d[k]!==undefined&&d[k]!=="");if(!ok)console.warn("[kristo] dish skipped (missing keys):",d.id||d);return ok&&d.available!==false;});data.dishes.forEach((d)=>{d.price=priceOf(d.id);});data.drinks=(data.drinks||[]).filter((d)=>d.available!==false);data.drinks.forEach((d)=>{d.price=priceOf(d.id);});return data;}
export function renderError(){const main=$("#snap");main.innerHTML=`
    <section class="screen" data-mood="paper">
      <div class="error-card">
        <h2>${t("errorTitle")}</h2>
        <p>${t("errorBody")}</p>
      </div>
    </section>`;}
export function render(){const main=$("#snap");$$(".screen",main).forEach((s,i)=>{if(i>0)s.remove();});const st=story.getStory();const append=(node,rail)=>{if(!node)return;if(rail)node.dataset.rail=rail;main.append(node);};renderHeroCategories();const catLabel=(id)=>{const cat=data.categories?.find((c)=>c.id===id);return cat?t(cat.label):id;};const tpl=$("#dish-template");const favs=new Set(storage.get("kristo:favorites",[]));if(st)append(story.buildWelcome(),"welcome");const seen=new Set();(data.categories||[]).forEach((cat)=>{const dishes=data.dishes.filter((d)=>d.category===cat.id);if(!dishes.length&&!cat.alwaysShow)return;append(story.buildCategoryIntro(cat),`cat-${cat.id}`);dishes.forEach((dish)=>{seen.add(dish.id);append(buildDish(dish,tpl,catLabel,favs),`cat-${cat.id}`);});});const orphans=data.dishes.filter((d)=>!seen.has(d.id));if(orphans.length){console.warn("[kristo] dishes without a known category:",orphans.map((d)=>d.id));orphans.forEach((dish)=>append(buildDish(dish,tpl,catLabel,favs),"end"));}
if(data.drinks.length)append(renderDrinks(),"drinks");if(st){append(story.buildOrder(data.restaurant||{}),"end");append(story.buildClosing(data.restaurant||{}),"end");}
emit("menu:rendered",{dishes:data.dishes});}
function renderHeroCategories(){const wrap=$(".hero__cats");if(!wrap)return;wrap.innerHTML="";const hasDishes=(catId)=>data.dishes.some((d)=>d.category===catId);(data.categories||[]).forEach((cat)=>{if(!hasDishes(cat.id)&&!cat.alwaysShow)return;const tile=document.createElement("button");tile.type="button";tile.className=cat.alwaysShow?"hero__cat hero__cat--daily":"hero__cat";tile.dataset.goto=`cat-${cat.id}`;tile.textContent=t(cat.label);wrap.append(tile);});if(data.drinks.length){const tile=document.createElement("button");tile.type="button";tile.className="hero__cat";tile.dataset.goto="drinks";tile.textContent=t("drinksTitle");wrap.append(tile);}}
function buildDish(dish,tpl,catLabel,favs){const node=tpl.content.firstElementChild.cloneNode(true);node.id=dish.id;node.dataset.mood=dish.background;node.dataset.presentation=dish.presentation||"plate";node.setAttribute("aria-label",t(dish.name));const m=dish.mobile||{};node.dataset.mImg="top";node.dataset.mAlign=m.textAlign==="center"?"center":"start";node.dataset.mSize=m.imageScale==="large"?"large":"regular";$(".dish__texture",node).textContent=dish.texture||(dish.subtitle?.en||"KRISTO").split(" ").reduce((a,b)=>(b.length>a.length?b:a));mountFloats(node,dish);const img=$(".dish__img",node);img.alt=t(dish.name);img.dataset.image=dish.image;if(m.objectPosition)img.style.setProperty("--obj-pos",m.objectPosition);$(".dish__kicker",node).textContent=catLabel(dish.category);$(".dish__name .reveal__inner",node).textContent=t(dish.name);const sub=$(".dish__subtitle",node);const accent=getLang()==="ar"?dish.subtitle?.en:dish.subtitle?.ar;if(accent){const span=$("span",sub);span.textContent=accent;if(getLang()==="ar"){span.lang="en";span.dir="ltr";}else{span.lang="ar";span.dir="rtl";}}else sub.remove();const insp=$(".dish__inspiration",node);if(dish.inspiration)insp.textContent=t(dish.inspiration);else insp.remove();$(".dish__desc",node).textContent=t(dish.description);const ul=$(".dish__ingredients",node);(t(dish.ingredients)||[]).forEach((ing)=>{const li=document.createElement("li");li.textContent=ing;ul.append(li);});if(dish.price!=null){$(".dish__price-num",node).textContent=dish.price;$(".dish__price-cur",node).textContent=t("sar");}else{$(".dish__price",node).remove();}
const cal=$(".dish__cal",node);if(dish.calories)cal.innerHTML=`${ICONS.flame}<span>${dish.calories} ${t("kcal")}</span>`;else cal.remove();const time=$(".dish__time",node);if(dish.prepTime)time.innerHTML=`${ICONS.clock}<span>${dish.prepTime} ${t("min")}</span>`;else time.remove();const badges=$(".dish__badges",node);const badge=(icon,label)=>{const b=document.createElement("span");b.className="badge";b.innerHTML=`${icon}<span>${label}</span>`;badges.append(b);};if(dish.chefChoice)badge(ICONS.toque,t("chefChoice"));if(dish.vegetarian)badge(ICONS.leaf,t("vegetarian"));if(dish.spicy)badge(ICONS.chili,t("spicy"));const orderBtn=$(".dish__order",node);orderBtn.textContent=t("order");orderBtn.addEventListener("click",()=>openSheet(dish,orderBtn));const favBtn=$(".dish__fav",node);favBtn.innerHTML=ICONS.heart;const isFav=favs.has(dish.id);favBtn.setAttribute("aria-pressed",String(isFav));favBtn.setAttribute("aria-label",t(isFav?"unfavorite":"favorite"));favBtn.addEventListener("click",()=>toggleFavorite(dish.id,favBtn));const shareBtn=$(".dish__share",node);shareBtn.innerHTML=ICONS.share;shareBtn.setAttribute("aria-label",t("share"));shareBtn.addEventListener("click",()=>{if(window.gsap){const icon=shareBtn.querySelector("svg");gsap.fromTo(icon,{y:0},{y:-3,duration:0.16,ease:"power2.out",yoyo:true,repeat:1});}
share(dish);});return node;}
function renderDrinks(){const s=document.createElement("section");s.className="screen drinks";s.id="drinks";s.dataset.mood="paper";s.dataset.animate="";s.setAttribute("aria-label",t("drinksTitle"));s.innerHTML=`
    <div class="drinks__head">
      <p class="dish__kicker drinks__kicker" data-enter="rise" data-enter-at="0">${t("drinksKicker")}</p>
      <h2 class="drinks__title"><span class="reveal"><span class="reveal__inner" data-enter="mask" data-enter-at="0.08">${t("drinksTitle")}</span></span></h2>
    </div>
    <div class="drinks__strip" role="list" tabindex="0" aria-label="${t("drinksTitle")}"></div>`;const strip=$(".drinks__strip",s);data.drinks.forEach((drink,i)=>{const card=document.createElement("div");card.className="drink-card";card.setAttribute("role","listitem");if(i<6){card.dataset.enter="pop";card.dataset.enterAt=(0.25+i*0.05).toFixed(2);}
card.innerHTML=`
      <img alt="${t(drink.name)}" loading="lazy" decoding="async">
      <p class="drink-card__name">${t(drink.name)}</p>
      ${drink.price != null ? `<p class="drink-card__price">${drink.price}${t("sar")}</p>` : ""}`;const img=$("img",card);img.dataset.image=drink.image;img.dataset.dir="assets/images/drinks/";img.dataset.sizes="80px";strip.append(card);});return s;}
function toggleFavorite(id,btn){const favs=new Set(storage.get("kristo:favorites",[]));const nowFav=!favs.has(id);if(nowFav)favs.add(id);else favs.delete(id);storage.set("kristo:favorites",[...favs]);btn.setAttribute("aria-pressed",String(nowFav));btn.setAttribute("aria-label",t(nowFav?"unfavorite":"favorite"));if(!window.gsap)return;gsap.killTweensOf(btn);if(nowFav){gsap.timeline().to(btn,{scale:1.28,duration:0.14,ease:"power2.out"}).to(btn,{scale:0.94,duration:0.12,ease:"power2.inOut"}).to(btn,{scale:1.1,duration:0.12,ease:"power2.inOut"}).to(btn,{scale:1,duration:0.18,ease:"power2.out"});}else{gsap.fromTo(btn,{scale:0.9},{scale:1,duration:0.25,ease:"power2.out"});}}
async function share(dish){const url=`${location.origin}${location.pathname}#${dish.id}`;const payload={title:`كريستو — ${t(dish.name)}`,text:t(dish.description),url};try{if(navigator.share){await navigator.share(payload);return;}
await navigator.clipboard.writeText(url);toast(t("linkCopied"));}catch(err){if(err?.name==="AbortError")return;try{await navigator.clipboard.writeText(url);toast(t("linkCopied"));}catch{toast(url);}}}
let lastTrigger=null;export function openSheet(dish,trigger){const sheet=$("#order-sheet");lastTrigger=trigger;$("#sheet-title").textContent=t(dish.name);const linksEl=$("#sheet-links");const merged={...(data.restaurant?.orderLinks||{})};for(const[app,url]of Object.entries(dish.orderLinks||{})){if(url)merged[app]=url;}
const entries=Object.entries(merged).filter(([,url])=>url&&!url.includes("REPLACE_ME"));linksEl.innerHTML=entries.length?entries.map(([app,url])=>`<a href="${url}" target="_blank" rel="noopener">${appLabel(app)}</a>`).join(""):`<p class="sheet__sub">${getLang() === "ar" ? "روابط الطلب تُضاف قريباً" : "Ordering links coming soon"}</p>`;sheet.showModal();if(window.gsap){gsap.fromTo(sheet,{y:"100%"},{y:0,duration:0.38,ease:"power3.out"});}else{sheet.style.transform="translateY(0)";}}
export function initSheet(){const sheet=$("#order-sheet");const close=()=>{if(!sheet.open)return;const done=()=>{sheet.close();lastTrigger?.focus({preventScroll:true});};if(window.gsap){gsap.to(sheet,{y:"100%",duration:0.26,ease:"power2.in",onComplete:done});}else done();};$(".sheet__close",sheet).addEventListener("click",close);sheet.addEventListener("cancel",(e)=>{e.preventDefault();close();});sheet.addEventListener("click",(e)=>{if(e.target!==sheet)return;const r=sheet.getBoundingClientRect();const inside=e.clientX>=r.left&&e.clientX<=r.right&&e.clientY>=r.top&&e.clientY<=r.bottom;if(!inside)close();});}